INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('138-4-000066',1,1,1,1,1,'좁은 지하 구조로 인한 운전 난이도가 높습니다. 제한된 공간에서 운전 스트레스가 크며, 후기에서 확인된 과도한 보행자 충돌 및 갈등 사례로 보아 주차장 이용객들의 교통 예절이 좋지 않은 편입니다. 초보운전자에게는 강력히 비추천합니다.','null','2026-03-07 13:17:17','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('KA-20516447',1,1,1,1,1,'운전면허 굴절코스 수준의 극도로 좁은 설계입니다. 출입구가 S자 형태로 경사로 진입이 어렵고, 커브 구간의 연석이 매우 위험합니다. 초보운전자는 강력히 비추천하며, 경험이 많은 운전자도 신중한 조작이 필요합니다.','null','2026-03-07 13:17:00','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('KA-20563023',1,1,1,1,1,'극도로 좁은 진입로와 통로로 인해 초보운전자에게 매우 위험합니다. 사이드미러 손상, 연석 긁힘, 후진 시 뒷차 압박 등 다중 위험요소가 있습니다. 큼직한 차량이나 초보운전자는 반드시 피해야 하며, 경험 많은 운전자도 신중한 조작이 필요합니다.','null','2026-03-07 13:16:55','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('KA-492383927',1,1,1,1,1,'역대급 난이도의 헬 주차장입니다. 연석 휠 손상이 빈번하게 보고되고 있어 초보운전자는 피하시기를 강력히 권장합니다. 진입로부터 주차면, 통로 전반에 걸쳐 매우 협소하고 복잡한 구조로 판단됩니다. 경험 많은 운전자도 조심스러워하는 수준입니다.','null','2026-03-07 13:17:27','null','null','null',1);
INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1267337295_375080801',1,1,1,1,1,'제공된 후기는 주차장 난이도와 무관한 아파트 선택 상담 내용입니다. 주차장 특성에 대한 구체적 정보가 없어 평가 불가능하나, ''극악 난이도'' 큐레이션 사유와 ''hell 주차장'' 태그를 고려할 때 초보운전자에게 강력히 비추천합니다.','null','2026-03-07 13:46:50','null','null','null',1);
