INSERT OR IGNORE INTO reviews (parking_lot_id,entry_score,space_score,passage_score,exit_score,overall_score,comment,visited_at,created_at,user_id,guest_nickname,ip_hash,is_seed) VALUES ('NV-1269749151_375637067',1,1,1,1,1,'1979년 건설된 건물로 당시 소형차 기준으로 설계되어 현대 차량에는 매우 좁습니다. 진입로와 통로 모두 협소하여 초보운전자는 접근 불가 수준입니다. 벤틀리 같은 대형차는 물론 일반 중형차도 진입 및 주차에 심각한 어려움이 예상됩니다.','null','2026-03-07 13:46:46','null','null','null',1);
